    if (n == 1 && m == 1) return 1
    if (k >= (n - 1) / 2 && k >= (m - 1) / 2) return 1

    var res = 0L
    var i = 0L
    while (i < n) {
        var j = 0L
        while (j < m) {
            val row = i + k
            val col = j + k
            if (row >= n || col >= m) {
                j += 2 * k + 1
                continue
            }
            res++
            i = row + 1
            j = col + 1
        }
        i += 2 * k + 1
    }
    return res
}
